import{_ as t,o as e,c as a,ae as o}from"./chunks/framework.Dzr56EFm.js";const c=JSON.parse('{"title":"设计趋势 - 2026-03-18","description":"","frontmatter":{"date":"2026-03-18T00:00:00.000Z","category":"UX Trend"},"headers":[],"relativePath":"daily/2026-03-18-uxtrend.md","filePath":"daily/2026-03-18-uxtrend.md"}'),n={name:"daily/2026-03-18-uxtrend.md"};function s(i,r,p,g,h,d){return e(),a("div",null,[...r[0]||(r[0]=[o('<h1 id="设计趋势-2026-03-18" tabindex="-1">设计趋势 - 2026-03-18 <a class="header-anchor" href="#设计趋势-2026-03-18" aria-label="Permalink to &quot;设计趋势 - 2026-03-18&quot;">​</a></h1><blockquote><p>AI交互方式、Prompt UX、Agent UX、Workflow</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日设计趋势资讯汇总：Cursor AI推动网页设计快速可视化，AI助手的交互设计成为UX设计师新课题。用户体验正向减少用户行为转变，Figma预测2026年网页设计将更智能个性化。最值得关注：AI技术在网页设计和用户体验设计中的应用，预示着设计领域的智能化和个性化趋势。</p><hr><h3 id="_1-利用cursor-ai进行网页设计" tabindex="-1">1. 利用Cursor AI进行网页设计 <a class="header-anchor" href="#_1-利用cursor-ai进行网页设计" aria-label="Permalink to &quot;1. 利用Cursor AI进行网页设计&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/ux-planet/vibe-coding-for-web-with-cursor-ai-0059aa5e5803" target="_blank" rel="noreferrer">Vibe Coding for web with Cursor AI | by Nick Babich | UX Planet</a></p><p><strong>一句话摘要</strong>: Cursor AI助力快速可视化构建，需迭代优化。</p><p><strong>能解决什么问题</strong>: 解决设计初期快速原型制作和收集反馈的需求。</p><p><strong>产品应用</strong>: 适用于初步设计阶段，需进一步迭代完善才能用于实际产品。</p><p><strong>示例场景</strong>: 设计师使用Cursor AI快速生成网页原型。</p><hr><h3 id="_2-ai助手的用户体验设计要点" tabindex="-1">2. AI助手的用户体验设计要点 <a class="header-anchor" href="#_2-ai助手的用户体验设计要点" aria-label="Permalink to &quot;2. AI助手的用户体验设计要点&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/what-ux-designers-should-understand-about-ai-agents-ded69d00ebf6" target="_blank" rel="noreferrer">What UX Designers Should Understand About AI Agents - Medium</a></p><p><strong>一句话摘要</strong>: UX设计师需理解AI助手的交互设计和用户参与过程。</p><p><strong>能解决什么问题</strong>: 解决AI助手在交互过程中的步骤展示、用户干预时机和需求解释问题。</p><p><strong>产品应用</strong>: 适用于需要AI助手参与的产品设计，如智能客服、自动化办公助手等。</p><p><strong>示例场景</strong>: 智能助手协助用户完成市场研究报告的准备。</p><hr><h3 id="_3-代理型用户体验的兴起-用户体验的演变" tabindex="-1">3. 代理型用户体验的兴起：用户体验的演变 <a class="header-anchor" href="#_3-代理型用户体验的兴起-用户体验的演变" aria-label="Permalink to &quot;3. 代理型用户体验的兴起：用户体验的演变&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/the-rise-of-agentic-ux-why-user-experience-is-evolving-from-interaction-to-collaboration-945b06b31124" target="_blank" rel="noreferrer">The Rise of Agentic UX: Why User Experience Is Evolving ... - Medium</a></p><p><strong>一句话摘要</strong>: 用户体验正从指导用户行为转变为减少甚至消除用户行为。</p><p><strong>能解决什么问题</strong>: 解决用户操作繁琐、效率低下的问题，提升用户体验。</p><p><strong>产品应用</strong>: 可以应用到智能助手、自动化工作流程等产品中，通过AI代理简化用户任务。</p><p><strong>示例场景</strong>: 用户通过语音命令启动30天健身计划，AI代理自动规划、跟踪并提醒。</p><hr><h3 id="_4-2026年顶级网页设计趋势-figma" tabindex="-1">4. 2026年顶级网页设计趋势 - Figma <a class="header-anchor" href="#_4-2026年顶级网页设计趋势-figma" aria-label="Permalink to &quot;4. 2026年顶级网页设计趋势 - Figma&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.figma.com/resource-library/web-design-trends/" target="_blank" rel="noreferrer">Top Web Design Trends for 2026 - Figma</a></p><p><strong>一句话摘要</strong>: AI技术推动网页设计向智能化和个性化发展</p><p><strong>能解决什么问题</strong>: 提高网站交互性、个性化体验和用户满意度</p><p><strong>产品应用</strong>: 实际产品中可通过AI工具实现智能布局、语音命令和交互代理</p><p><strong>示例场景</strong>: 使用Figma Make测试智能布局和聊天机器人流程</p><hr><h3 id="_5-2026年最流行的体验设计趋势" tabindex="-1">5. 2026年最流行的体验设计趋势 <a class="header-anchor" href="#_5-2026年最流行的体验设计趋势" aria-label="Permalink to &quot;5. 2026年最流行的体验设计趋势&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/the-most-popular-experience-design-trends-of-2026-3ca85c8a3e3d" target="_blank" rel="noreferrer">The most popular experience design trends of 2026 - UX Collective</a></p><p><strong>一句话摘要</strong>: AI引入速度和模糊性，组织结构难以适应。</p><p><strong>能解决什么问题</strong>: 设计组织急于使用AI，未重新定义设计流程和质量标准。</p><p><strong>产品应用</strong>: 可以应用，需重新定义设计流程、质量标准和决策权。</p><p><strong>示例场景</strong>: 使用AI生成的设计系统创建个性化用户体验。</p><hr><h3 id="_6-光标创新-通过引人入胜的光标交互提升用户体验" tabindex="-1">6. 光标创新：通过引人入胜的光标交互提升用户体验 <a class="header-anchor" href="#_6-光标创新-通过引人入胜的光标交互提升用户体验" aria-label="Permalink to &quot;6. 光标创新：通过引人入胜的光标交互提升用户体验&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@vishnuharidaskarinatt/cursor-innovation-enhancing-user-experience-with-engaging-cursor-interactions-b1cee9d8b82a" target="_blank" rel="noreferrer">Cursor Innovation: Enhancing User Experience with Engaging ...</a></p><p><strong>一句话摘要</strong>: 光标设计将成为UX/UI设计中的重要方面。</p><p><strong>能解决什么问题</strong>: 提升网站导航的个性化和互动性，增强用户体验。</p><p><strong>产品应用</strong>: 适用于网站设计，通过个性化光标增强用户互动。</p><p><strong>示例场景</strong>: 在线购物网站使用光标变化提示可点击区域。</p><hr><h3 id="_7-在chatgpt中直接构建应用的新app-sdk" tabindex="-1">7. 在ChatGPT中直接构建应用的新App SDK <a class="header-anchor" href="#_7-在chatgpt中直接构建应用的新app-sdk" aria-label="Permalink to &quot;7. 在ChatGPT中直接构建应用的新App SDK&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/@kenzic/build-apps-directly-inside-chatgpt-with-the-new-app-sdk-e789ef0b5997" target="_blank" rel="noreferrer">Build Apps Directly Inside ChatGPT with the New App SDK - Medium</a></p><p><strong>一句话摘要</strong>: ChatGPT App SDK允许开发者在聊天中直接构建应用。</p><p><strong>能解决什么问题</strong>: 将聊天界面转变为可以运行应用的环境，提升交互性和功能。</p><p><strong>产品应用</strong>: 适用于需要快速、上下文相关任务的应用，如预订、查询等。</p><p><strong>示例场景</strong>: 在聊天中直接预订餐厅或查询订单状态。</p><hr><h3 id="_8-ux设计师指南-如何构建有效的提示" tabindex="-1">8. UX设计师指南：如何构建有效的提示 <a class="header-anchor" href="#_8-ux设计师指南-如何构建有效的提示" aria-label="Permalink to &quot;8. UX设计师指南：如何构建有效的提示&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://uxdesign.cc/a-ux-designer-guide-to-prompt-f045cd839489" target="_blank" rel="noreferrer">A UX designer guide to prompt - UX Collective</a></p><p><strong>一句话摘要</strong>: UX设计师通过构建有效提示，促进人机对话。</p><p><strong>能解决什么问题</strong>: 解决预训练AI模型理解人类请求的问题。</p><p><strong>产品应用</strong>: 适用于需要AI模型理解和执行复杂指令的产品。</p><p><strong>示例场景</strong>: 设计一个聊天机器人，通过提示理解用户需求。</p><hr><h3 id="_9-如何使用chatgpt的新图像生成器创建ui" tabindex="-1">9. 如何使用ChatGPT的新图像生成器创建UI <a class="header-anchor" href="#_9-如何使用chatgpt的新图像生成器创建ui" aria-label="Permalink to &quot;9. 如何使用ChatGPT的新图像生成器创建UI&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/how-i-created-ui-with-chatgpts-new-image-generator-4o-d52389a5833e" target="_blank" rel="noreferrer">How I created UI with ChatGPT&#39;s new image generator (4o) - Medium</a></p><p><strong>一句话摘要</strong>: 利用ChatGPT的图像生成器改进UI设计</p><p><strong>能解决什么问题</strong>: 解决UI设计中的视觉呈现和代码实现问题</p><p><strong>产品应用</strong>: 可以应用到产品设计中，通过生成视觉原型和代码</p><p><strong>示例场景</strong>: 设计一个响应式的网页界面</p><hr><h3 id="_10-从用户体验到人工智能体验-为人类和ai代理设计" tabindex="-1">10. 从用户体验到人工智能体验：为人类和AI代理设计 <a class="header-anchor" href="#_10-从用户体验到人工智能体验-为人类和ai代理设计" aria-label="Permalink to &quot;10. 从用户体验到人工智能体验：为人类和AI代理设计&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://medium.com/design-bootcamp/from-ux-to-ax-designing-for-humans-and-ai-agents-96f34e44c443" target="_blank" rel="noreferrer">From UX to AX: Designing for Humans and AI Agents - Medium</a></p><p><strong>一句话摘要</strong>: AI代理通过API直接查询数据，提升人类和AI的工作效率。</p><p><strong>能解决什么问题</strong>: 提高AI代理在产品生态系统中的导航、理解和行动效率。</p><p><strong>产品应用</strong>: 适用于需要AI自动化处理数据和任务的产品，如电商推荐系统。</p><p><strong>示例场景</strong>: AI代理快速查询并推荐符合用户需求的鞋子。</p><hr>',75)])])}const u=t(n,[["render",s]]);export{c as __pageData,u as default};
